query:
SELECT 'handLeaks' AS tbl, COUNT(*) AS cnt FROM handLeaks
UNION ALL
SELECT 'leaks', COUNT(*) FROM leaks;

SELECT id, name, category, status FROM leaks ORDER BY id;

SELECT hl.handId, hl.leakId, l.name AS leakName FROM handLeaks hl LEFT JOIN leaks l ON hl.leakId = l.id ORDER BY hl.handId;

